def load_lines(log_path):
    """Read the whole log in one buffered read and split it into lines."""
    fd = os.open(log_path, os.O_RDONLY)
    try:
        data = os.read(fd, os.fstat(fd).st_size)
    finally:
        os.close(fd)
    text = data.decode()
    if text.endswith("\n"):
        text = text[:-1]
    if text == "":
        return []
    return text.split("\n")

